import { Component, OnInit } from '@angular/core';
import { FinancialsService } from '../../services/financials.service';
import { FinancialRecord } from '../../core/data.models';
import { Observable } from 'rxjs';

@Component({
  selector: 'app-financials-list',
  templateUrl: './financials-list.component.html'
})
export class FinancialsListComponent implements OnInit {
  items$: Observable<FinancialRecord[]>;

  constructor(private svc: FinancialsService) {
    this.items$ = this.svc.list$;
  }

  ngOnInit(): void {}

  remove(id: string) {
    this.svc.remove(id);
  }
}
<div class="header">
  <h2>Financials</h2>
  <button class="btn" routerLink="new">Add</button>
</div>

<div class="grid">
  <ng-container *ngIf="items$ | async as list">
    <div *ngIf="list.length === 0" class="card">No financial records. Click Add to create one.</div>
    <div *ngFor="let f of list" class="card">
      <h3>{{f.title}}</h3>
      <div class="small">{{f.type}} | {{f.currency || 'USD'}} {{f.amount}}</div>
      <div style="margin-top:8px">Due: {{f.dueDate || '—'}} | Recurring: {{f.recurring ? 'Yes' : 'No'}}</div>
      <div style="margin-top:8px">
        <a [routerLink]="[f.id]">View</a>
        <a [routerLink]="[f.id, 'edit']" style="margin-left:8px">Edit</a>
        <button style="margin-left:8px" (click)="remove(f.id)">Delete</button>
      </div>
    </div>
  </ng-container>
</div>
